import{_ as s,C as t,o as h,c,j as e,a as i,E as o,a3 as p}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第35章 怀玉","description":"帛书德篇第35章 · 怀玉（通行本第70章）","frontmatter":{"title":"帛书第35章 怀玉","description":"帛书德篇第35章 · 怀玉（通行本第70章）","category":"guide","aliases":["帛书第35章","马王堆老子35","通行本第70章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/dao-de-jing-boshu/chapter-35.md","filePath":"daoism/dao-de-jing-boshu/chapter-35.md","lastUpdated":1780591578000}'),u={name:"daoism/dao-de-jing-boshu/chapter-35.md"};function m(b,a,x,_,g,f){const r=t("DaoReadingPrelude"),n=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),c("div",null,[a[0]||(a[0]=e("h1",{id:"帛书老子第35章",tabindex:"-1"},[i("帛书老子第35章 "),e("a",{class:"header-anchor",href:"#帛书老子第35章","aria-label":'Permalink to "帛书老子第35章"'},"​")],-1)),o(r,{title:"第35章 怀玉",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第70章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第35章"},{label:"对照",text:"通行本第70章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),o(n,{paragraphs:["吾言甚易知也 甚易行也","而人莫之能知也 而莫之能行也","言有君 事有宗","夫唯无知也 是以不我知","知我者希 则我贵矣","是以圣人被褐而怀玉"]}),o(l,{lines:[{text:"吾言甚易知也 甚易行也 而人莫之能知也 而莫之能行也",tone:"起",guide:"我的话很容易懂，也很容易做——但世人不能懂，也不能做。帛书以最朴素的感慨开篇。"},{text:"言有君 事有宗",tone:"理",guide:"言论有主旨，行事有根源——帛书指出言行应有根基，不能浮于表面。"},{text:"夫唯无知也 是以不我知 知我者希 则我贵矣",tone:"叹",guide:"正因为世人无知，所以才不了解我；了解我的人越少，我就越珍贵——老子以被误解为荣。"},{text:"是以圣人被褐而怀玉",tone:"收",guide:"所以圣人穿着粗布衣服（褐），怀里却揣着美玉——外表朴素，内在珍贵。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),o(d,{items:[{term:"被褐",pinyin:["pī","hè"],meaning:"穿着粗布衣服。被通披，褐即粗布衣。",context:"被褐怀玉——外表朴素、内在珍贵，是老子对得道者的经典画像。"},{term:"怀玉",pinyin:["huái","yù"],meaning:"怀揣美玉。被褐怀玉——外表不起眼，内在却藏着无价之宝。",context:"此四字成为中国文化中「大隐隐于市」的原型意象。"}]}),a[3]||(a[3]=p('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「怀玉」，帛书此章围绕「吾言易知易行」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第70章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(u,[["render",m]]);export{q as __pageData,k as default};
